# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

def check_permission(user_id, file_id):
    conn = sqlite3.connect('permissions.db')
    cursor = conn.cursor()
    cursor.execute("SELECT access_level FROM user_permissions WHERE user_id = ? AND file_id = ?", (user_id, file_id))
    result = cursor.fetchone()
    conn.close()
    return result is not None and result[0] >= 1  # Assuming 1 is the minimum access level required

def read_file(user_id, file_id):
    if check_permission(user_id, file_id):
        with open(f"files/{file_id}.txt", "r") as file:
            return file.read()
    else:
        raise PermissionError("You do not have permission to access this file.")